**Fix:** Single pass over transactions. Build composite key `${userId}|${amount}|${date}` and accumulate into a `Map<string, DuplicateGroup>`. After the pass, filter out keys with only one transaction (non-duplicates).

```typescript
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, DuplicateGroup>();

  for (const t of transactions) {
    const key = `${t.userId}|${t.amount}|${t.date}`;
    const existing = map.get(key);
    if (existing) {
      existing.transactions.push(t);
    } else {
      map.set(key, { key, transactions: [t] });
    }
  }

  return Array.from(map.values()).filter(g => g.transactions.length >= 2);
}
```

**Correctness preserved:**
