  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );
  return transactions.filter(t => pattern.test(t.description));
}
```

**Correctness preserved:**
- The same regex-escape logic is applied.
- Case-insensitive flag `"i"` retained.
- Special-character test (`"$5.00"`) still works.
- Empty result for no matches (`filter` returns `[]`).

---

### Step 6 â€” `processAll` (lines 237â€“250): no structural change needed

This function simply calls the five functions above sequentially. After the optimizations above, `processAll` on 20k transactions will comfortably complete well under 200 ms. No changes required here.

